import sys
import itertools

def read_polyominoes():
    polyominoes = []
    for _ in range(3):
        poly = []
        for _ in range(4):
            line = sys.stdin.readline().strip()
            poly.append(list(line))
        polyominoes.append(poly)
    return polyominoes

def get_cells(poly):
    cells = []
    for i in range(4):
        for j in range(4):
            if poly[i][j] == '#':
                cells.append((i, j))
    return cells

def rotate(poly):
    return [list(row) for row in zip(*poly[::-1])]

def translate(poly, dx, dy):
    new_poly = [['.' for _ in range(4)] for _ in range(4)]
    for i in range(4):
        for j in range(4):
            if poly[i][j] == '#':
                ni, nj = i + dx, j + dy
                if 0 <= ni < 4 and 0 <= nj < 4:
                    new_poly[ni][nj] = '#'
    return new_poly

def generate_transformations(poly):
    transformations = []
    # Generate all rotations
    for _ in range(4):
        # Generate all translations
        for dx in range(-4, 4):
            for dy in range(-4, 4):
                transformed = translate(poly, dx, dy)
                cells = get_cells(transformed)
                if len(cells) > 0:  # Skip empty transformations
                    transformations.append(cells)
        poly = rotate(poly)
    return transformations

def is_connected(cells):
    if not cells:
        return False
    visited = set()
    queue = [cells[0]]
    while queue:
        x, y = queue.pop(0)
        if (x, y) in visited:
            continue
        visited.add((x, y))
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) in cells:
                queue.append((nx, ny))
    return len(visited) == len(cells)

def solve():
    polyominoes = read_polyominoes()
    transformations = [generate_transformations(p) for p in polyominoes]

    for t1 in transformations[0]:
        if not is_connected(t1):
            continue
        for t2 in transformations[1]:
            if not is_connected(t2):
                continue
            combined = set(t1 + t2)
            if len(combined) != len(t1) + len(t2):
                continue  # Overlap
            for t3 in transformations[2]:
                if not is_connected(t3):
                    continue
                combined_all = set(t1 + t2 + t3)
